import { screen, waitFor } from "@testing-library/react";
import { renderWithProviders } from "./helpers";
import { MarketAnalytics } from "@/features/analytics";
import * as api from "@/lib/api/client";

vi.mock("@/lib/api/client");

const mockAnalytics = {
  market_id: "m1",
  total_volume: 50000,
  trade_count: 120,
